const API = "http://10.85.43.200:3000";

// REGISTER
async function register() {
  const username = document.getElementById("username").value;
  const password = document.getElementById("password").value;

  const res = await fetch(API + "/register", {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({ username, password })
  });

  const data = await res.json();
  document.getElementById("msg").innerText = data.message;
}

// LOGIN
async function login() {
  const username = document.getElementById("username").value;
  const password = document.getElementById("password").value;

  const res = await fetch(API + "/login", {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({ username, password })
  });

  const data = await res.json();

  if (data.success) {
    window.location.href = "dashboard.html";
  } else {
    document.getElementById("msg").innerText = "Invalid Login ❌";
  }
}

// LOAD DASHBOARD
if (window.location.pathname.includes("dashboard.html")) {
  fetch(API + "/dashboard")
    .then(res => res.json())
    .then(data => {
      document.getElementById("steps").innerText = data.steps;
      document.getElementById("calories").innerText = data.calories;
      document.getElementById("sleep").innerText = data.sleep;
      document.getElementById("score").innerText = data.healthScore;
    });
}